import { 運筆 } from '../bi.js';
import { 節之, 沿, 肢面, 環褶 } from '../gujia.js';
import { 月輪, 頭光, 蓮華座, 菩薩開臉, 點睛, 垂埵耳, 頸三道, 寶髻, 垂髮, 頸瓔, 胸瓔, 臂釧, 腕釧, 執杵手, 執鈴手, 五鈷杵, 五鈷鈴, 仰足, } from '../bujian/index.js';
export const 金剛薩埵 = (bi) => {
    const { A, E, dot, dim } = bi;
    const 筆 = 運筆(bi);
    const { M, L, C, Qk, S, 骨, 衣, 細, 逸, 陰, 陽 } = 筆;
    // ── 立骨：先裸身之骨（膠囊：節 x/z/深；深惟定褶向與前後，不作透視）──────
    // 尊右臂（畫面左）：舉——前臂向觀者，深漸大
    const 右上臂 = { a: 節之(-12.4, 28.6, 1), b: 節之(-14.6, 43.0, 2), ra: 2.6, rb: 2.15 };
    const 右前臂 = { a: 節之(-14.6, 43.0, 2), b: 節之(-4.3, 36.9, 6), ra: 2.0, rb: 1.55 };
    // 尊左臂（畫面右）：垂——前臂下行至膝上之鈴
    const 左上臂 = { a: 節之(12.4, 28.6, 1), b: 節之(15.2, 46.3, 2), ra: 2.6, rb: 2.1 };
    const 左前臂 = { a: 節之(15.2, 46.3, 2), b: 節之(15.25, 55.9, 4), ra: 1.95, rb: 1.5 };
    // 股（趺坐）：胯出而至膝；右股承右足故深大
    const 左股 = { a: 節之(8.8, 53.5, 3), b: 節之(20.5, 61.8, 5), ra: 5.0, rb: 4.3 };
    const 右股 = { a: 節之(-8.8, 53.5, 4), b: 節之(-20.5, 61.8, 6), ra: 5.0, rb: 4.3 };
    // 脛：右脛在前（右足仰於左股），左脛在後
    const 右脛 = { a: 節之(-21.0, 62.4, 7), b: 節之(4.5, 60.9, 9), ra: 3.1, rb: 2.4 };
    const 左脛 = { a: 節之(21.0, 63.0, 5), b: 節之(-4.0, 63.4, 4), ra: 3.2, rb: 2.6 };
    // ── 光 ────────────────────────────────────────────────────────────────────
    月輪(bi);
    頭光(bi);
    // ── 天衣：右側掛肘而降，左側讓垂臂自臂後外颺；至座際翻飛 ─────────────────
    dim(0.65, () => 衣(() => {
        逸(() => {
            M(-14.75, 42.6);
            C(-17.7, 44.6, -18.3, 48.8, -17.8, 52.4);
            C(-17.4, 55.4, -18.0, 58.0, -17.35, 60.2);
            S();
            M(-15.9, 45.5);
            C(-16.5, 48.8, -16.3, 52.0, -16.7, 55.0);
            S();
        });
        M(-17.35, 60.2);
        C(-19.6, 58.6, -21.8, 57.9, -23.3, 58.8);
        Qk(-24.1, 59.5, -23.2, 60.6);
        C(-21.4, 62.0, -19.2, 62.1, -17.8, 61.5);
        S();
        細(() => { M(-19.5, 59.5); Qk(-20.9, 59.15, -22.1, 59.4); S(); });
        逸(() => {
            M(16.2, 44.8);
            C(18.4, 46.8, 18.8, 50.6, 18.2, 53.6);
            C(17.8, 56.1, 18.2, 58.4, 17.6, 60.2);
            S();
        });
        M(17.6, 60.2);
        C(19.8, 58.7, 22.0, 58.0, 23.5, 58.9);
        Qk(24.3, 59.6, 23.4, 60.7);
        C(21.6, 62.1, 19.4, 62.2, 18.0, 61.6);
        S();
        細(() => { M(19.7, 59.6); Qk(21.1, 59.25, 22.3, 59.5); S(); });
    }));
    // ── 座 ────────────────────────────────────────────────────────────────────
    蓮華座(bi);
    // ── 趺坐之體（希臘之眼重構，膝寬五十二指不動）：膝作球、股頂作棚、
    //    前脛作橫貫之圓柱——體先立而衣覆之；上緣於仰足與鈴處兩斷 ────────────────
    骨(() => {
        // 兩膝之球：圓渾成瘤（骨相圓滿——弧不露稜）
        M(-22.5, 60.9);
        C(-24.7, 61.3, -25.95, 62.6, -25.9, 64.1);
        C(-25.85, 65.8, -24.5, 67.1, -22.4, 67.7);
        S();
        M(22.3, 60.8);
        C(24.5, 61.2, 25.8, 62.5, 25.75, 64.0);
        C(25.7, 65.7, 24.3, 67.0, 22.2, 67.6);
        S();
        // 趺坐下緣＝前脛之腹：自左膝底右行，飽滿微沉，收於右膝底
        M(-22.4, 67.7);
        C(-15.5, 68.7, -6.0, 68.9, 1.5, 68.75);
        C(9.5, 68.6, 16.5, 68.3, 22.2, 67.6);
        S();
        // 趺坐上緣（後脛與股頂之際）：左段讓足、右段讓鈴
        M(-22.5, 60.9);
        C(-17.0, 60.3, -11.0, 60.1, -6.0, 59.8);
        Qk(-2.5, 59.6, 0, 59.6);
        Qk(2.4, 59.7, 4.6, 59.9);
        S();
        M(17.9, 60.55);
        Qk(20.2, 60.6, 22.3, 60.8);
        S();
    });
    // 前脛上緣（圓柱之上界，環褶所繞之體）與股頂之棚（承足承鈴之面）
    衣(() => {
        dim(0.75, () => { M(-19.2, 62.0); C(-13.0, 61.4, -5.5, 61.0, 3.9, 61.05); S(); });
        dim(0.55, () => {
            M(9.8, 55.6);
            C(12.4, 56.8, 15.6, 58.4, 18.2, 60.1);
            S();
            M(-9.8, 55.6);
            Qk(-12.3, 56.9, -14.3, 58.3);
            S();
        });
    });
    // ── 身軀：頸肩臂皆親筆之曲（骨架記深度惟定褶向；直軸膠囊之輪廓失肌之曲，
    //    故臂線仍親運——體積之用在褶，不在郭）────────────────────────────────
    骨(() => {
        // 頸柱
        M(-2.65, 20.9);
        Qk(-2.95, 22.6, -2.9, 24.1);
        S();
        M(2.65, 20.9);
        Qk(2.95, 22.6, 2.9, 24.1);
        S();
        // 僧帽肌之坡與三角肌之峰——肩圓滿（七處隆滿之二）：滿弧成丘，不露稜
        for (const d of [-1, 1]) {
            M(d * 2.9, 24.1);
            C(d * 5.8, 24.3, d * 9.0, 24.8, d * 11.2, 25.8);
            C(d * 12.6, 26.5, d * 13.35, 27.4, d * 13.4, 28.6);
            S();
        }
        // 尊右臂（畫面左＝陽側，線輕）：上臂垂→肘→前臂上抱入橫拳，端貼拳郭
        陽(() => {
            M(-13.4, 28.6);
            C(-14.3, 30.2, -14.55, 32.4, -14.35, 35.2);
            C(-14.15, 38.2, -14.6, 41.0, -14.7, 43.4);
            S();
            M(-13.4, 42.0);
            C(-10.4, 40.2, -7.6, 38.0, -6.0, 36.7);
            Qk(-4.4, 35.9, -3.3, 35.4);
            S();
        });
        M(-14.7, 43.4);
        C(-12.2, 42.8, -8.4, 40.8, -6.2, 39.2);
        Qk(-4.6, 38.6, -3.0, 38.1);
        S();
        // 尊左臂（畫面右＝陰側，線重）：上臂垂→肘微外→前臂下行，端貼覆拳之郭
        陰(() => {
            M(13.4, 28.6);
            C(14.4, 30.2, 14.75, 32.4, 14.65, 35.2);
            C(14.55, 38.6, 15.1, 43.0, 15.3, 46.5);
            S();
            M(15.3, 46.5);
            C(15.6, 49.5, 15.7, 52.0, 15.35, 54.2);
            Qk(15.1, 55.6, 16.0, 56.7);
            S();
        });
        M(12.6, 42.4);
        C(13.1, 45.0, 13.7, 49.5, 13.55, 53.2);
        Qk(13.45, 55.2, 14.3, 56.4);
        S();
        // 軀幹之側：腋→腰之收→胯之張（左陽右陰）
        陽(() => { M(-10.9, 32.4); C(-10.1, 36.5, -9.7, 40.5, -10.1, 46.5); Qk(-10.5, 50.0, -12.6, 53.0); S(); });
        陰(() => { M(10.9, 32.4); C(10.1, 36.5, 9.7, 40.5, 10.1, 46.5); Qk(10.5, 50.0, 12.6, 53.0); S(); });
    });
    // 胸腹之相：鎖骨微提、胸廓下緣淡痕（體之具體）、臍
    細(() => {
        M(-2.4, 25.7);
        Qk(-6.0, 26.3, -9.4, 25.9);
        S();
        M(2.4, 25.7);
        Qk(6.0, 26.3, 9.4, 25.9);
        S();
        bi.dim(0.5, () => {
            M(-5.6, 37.6);
            Qk(-3.9, 38.7, -2.0, 38.95);
            S();
            M(5.6, 37.6);
            Qk(3.9, 38.7, 2.0, 38.95);
            S();
        });
        M(0, 47.5);
        L(0, 48.4);
        S();
        A(0, 48.0, 0.4, Math.PI * 0.25, Math.PI * 0.75);
    });
    // ── 衣：裙束腰結帶；褶隨體轉——環褶繞股繞脛，放射褶循股面 ─────────────────
    衣(() => {
        // 裙腰雙線與結帶
        M(-10.3, 50.4);
        Qk(0, 49.5, 10.3, 50.4);
        S();
        M(-10.5, 51.6);
        Qk(0, 50.7, 10.5, 51.6);
        S();
        A(-3.4, 51.1, 0.6);
        逸(() => {
            M(-3.2, 51.8);
            Qk(-3.8, 53.6, -3.0, 55.4);
            S();
            M(-3.7, 51.8);
            Qk(-4.7, 53.4, -4.4, 55.0);
            S();
        });
        // 張力褶：自膝（支點）向胯，繃於股面——布之物理，非紋飾
        逸(() => {
            M(...肢面(右股, 0.88, -0.5));
            C(-14.0, 57.5, -8.5, 54.5, -4.6, 52.8);
            S();
            M(...肢面(右股, 0.97, 0.08));
            C(-15.5, 59.5, -9.5, 56.2, -5.2, 54.2);
            S();
            M(...肢面(左股, 0.8, -0.5));
            C(13.0, 56.8, 9.0, 54.4, 5.2, 52.8);
            S();
            M(...肢面(左股, 0.9, 0.05));
            C(14.5, 58.6, 10.0, 55.8, 5.8, 54.0);
            S();
        });
        // 環褶：繞前脛二道（右脛在前，弧鼓之向隨深——遠近之感自此出）；
        // 兩脛之間懸褶二重相和，後脛淡露一道
        逸(() => {
            環褶(bi, 筆, 右脛, 0.36, 0.74);
            環褶(bi, 筆, 右脛, 0.58, 0.78);
            bi.dim(0.7, () => 環褶(bi, 筆, 左脛, 0.44, 0.56, -0.85));
            M(-3.6, 56.2);
            Qk(0, 58.2, 3.6, 56.2);
            S();
            M(-2.1, 57.3);
            Qk(0, 58.4, 2.1, 57.3);
            S();
        });
        // 膝頭環褶：包膝之弧各一
        逸(() => {
            環褶(bi, 筆, 右股, 0.92, 0.55);
            環褶(bi, 筆, 左股, 0.92, 0.55);
        });
    });
    // ── 仰足（部件）：右足安左股，足底一搩之比，千輻輪居心 ───────────────────
    衣(() => { M(4.4, 59.9); Qk(5.0, 60.05, 5.4, 60.7); S(); }); // 踝橋
    仰足(bi, 5.6, 61.6, 7.2);
    // ── 帶：條帛自尊左肩斜貫，沒於執杵之拳後 ────────────────────────────────
    dim(0.75, () => 衣(() => 逸(() => {
        M(9.7, 26.3);
        C(7.4, 28.6, 3.9, 32.2, 0.5, 36.0);
        S();
        M(10.6, 27.2);
        C(8.4, 29.4, 4.9, 33.0, 1.4, 36.8);
        S();
        M(-4.2, 41.2);
        C(-6.1, 43.8, -8.3, 46.6, -9.7, 49.0);
        S();
        M(-3.3, 42.4);
        C(-5.2, 44.8, -7.1, 47.4, -8.5, 49.8);
        S();
        細(() => { M(6.4, 30.0); L(7.2, 30.8); S(); M(-6.3, 45.7); L(-5.6, 46.5); S(); });
    })));
    // ── 執杵鈴（部件）：杵鈴先落，拳覆其上 ───────────────────────────────────
    五鈷杵(bi, -1.6, 36.4, 0.2, 1.2);
    執杵手(bi, -1.5, 36.45, 0.2, 1.3);
    五鈷鈴(bi, 15.4, 60.6, 1, false);
    執鈴手(bi, 15.2, 57.7, 1.18);
    // ── 嚴：頸瓔胸瓔臂釧腕釧（位隨骨）────────────────────────────────────────
    頸瓔(bi);
    胸瓔(bi, { 滴z: 30.7 });
    臂釧(bi, -1, 12.1, 14.5, 33.4);
    臂釧(bi, 1, 12.1, 14.5, 33.4);
    腕釧(bi, [[-5.9, 36.3, -5.5, 37.4, -5.0, 38.6], [-5.1, 35.9, -4.7, 37.0, -4.2, 38.2]], [-5.2, 37.3]);
    腕釧(bi, [[13.75, 54.4, 14.65, 54.8, 15.55, 54.5], [13.85, 55.5, 14.75, 55.9, 15.65, 55.6]], [14.75, 55.2]);
    // ── 頭面：開臉 v2（經制）・耳・頸三道 ────────────────────────────────────
    菩薩開臉(bi, '雞子');
    垂埵耳(bi);
    頸三道(bi);
    // ── 五佛寶冠：帶綴珠，五化佛列坐 ─────────────────────────────────────────
    衣(() => {
        M(-5.5, 8.9);
        Qk(0, 7.7, 5.5, 8.9);
        S();
        M(-5.35, 7.7);
        Qk(0, 6.5, 5.35, 7.7);
        S();
        細(() => { for (const [bx, bz] of [[-4.4, 8.15], [-2.2, 7.55], [0, 7.3], [2.2, 7.55], [4.4, 8.15]])
            dot(bx, bz, 0.2); });
        const 化佛 = (px, pz, s) => {
            細(() => {
                A(px, pz - 1.05 * s, 0.42 * s);
                M(px - 0.85 * s, pz + 0.75 * s);
                C(px - 0.9 * s, pz - 0.35 * s, px - 0.55 * s, pz - 0.55 * s, px, pz - 0.55 * s);
                C(px + 0.55 * s, pz - 0.55 * s, px + 0.9 * s, pz - 0.35 * s, px + 0.85 * s, pz + 0.75 * s);
                S();
                M(px - 0.85 * s, pz + 0.75 * s);
                Qk(px, pz + 0.95 * s, px + 0.85 * s, pz + 0.75 * s);
                S();
                bi.dim(0.6, () => A(px, pz - 0.9 * s, 0.8 * s, Math.PI * 1.05, Math.PI * 1.95));
            });
        };
        化佛(0, 4.4, 1.0);
        化佛(-2.5, 5.0, 0.88);
        化佛(2.5, 5.0, 0.88);
        化佛(-4.7, 5.9, 0.78);
        化佛(4.7, 5.9, 0.78);
        for (const d of [-1, 1]) {
            dim(0.7, () => 細(() => {
                M(d * 5.8, 8.6);
                C(d * 7.9, 9.3, d * 8.3, 10.9, d * 8.9, 12.4);
                Qk(d * 9.25, 13.3, d * 8.7, 13.9);
                S();
            }));
        }
    });
    // ── 髮 ────────────────────────────────────────────────────────────────────
    寶髻(bi);
    垂髮(bi);
    // ── 點睛殿後：末筆是瞳（開眼即開光）──────────────────────────────────────
    點睛(bi);
    void 沿; // 骨架取樣之具備而未盡用者，候衣紋加密再取
};
